const allItems = $input.all();
const extractItem = allItems[0]?.json || {};
const petData = extractItem.data || extractItem;

const analysisItem = allItems[1]?.json || {};
const healthAnalysis = analysisItem.answer || analysisItem.markdown || analysisItem.text || '';

const triggerData = $('New Pet Record').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';

// Check vaccine expiry alerts
const today = new Date();
function daysUntil(dateStr) {
  if (!dateStr || dateStr === 'N/A') return null;
  const d = new Date(dateStr);
  if (isNaN(d)) return null;
  return Math.ceil((d - today) / (1000 * 60 * 60 * 24));
}

const rabiesDays     = daysUntil(petData.rabiesExpiry);
const dhppDays       = daysUntil(petData.dhppExpiry);
const bordetellaDays = daysUntil(petData.bordetellaExpiry);

const urgentAlerts = [];
[
  { name: 'Rabies',     days: rabiesDays,     expiry: petData.rabiesExpiry },
  { name: 'DHPP',       days: dhppDays,       expiry: petData.dhppExpiry },
  { name: 'Bordetella', days: bordetellaDays, expiry: petData.bordetellaExpiry }
].forEach(v => {
  if (v.days !== null) {
    if (v.days < 0)  urgentAlerts.push(`${v.name} EXPIRED (${v.expiry})`);
    else if (v.days <= 30) urgentAlerts.push(`${v.name} due in ${v.days} days`);
  }
});

const alertLevel = urgentAlerts.length > 0 ? 'ACTION NEEDED' : 'All Good';

return [{ json: {
  fileName, fileId,
  petName:               petData.petName              || 'Unknown',
  species:               petData.species              || 'N/A',
  breed:                 petData.breed                || 'N/A',
  age:                   petData.age                  || 'N/A',
  weight:                petData.weight               || 'N/A',
  ownerName:             petData.ownerName            || 'N/A',
  ownerPhone:            petData.ownerPhone           || 'N/A',
  clinicName:            petData.clinicName           || 'N/A',
  vetName:               petData.vetName              || 'N/A',
  visitDate:             petData.visitDate            || 'N/A',
  visitReason:           petData.visitReason          || 'N/A',
  diagnosis:             petData.diagnosis            || 'None',
  treatment:             petData.treatment            || 'None',
  vaccinesGiven:         petData.vaccinesGiven        || 'None',
  vaccinesUpToDate:      petData.vaccinesUpToDate     ? 'Yes' : 'No',
  vaccinesDueSoon:       petData.vaccinesDueSoon      || 'None',
  vaccinesExpired:       petData.vaccinesExpired      || 'None',
  rabiesExpiry:          petData.rabiesExpiry         || 'N/A',
  dhppExpiry:            petData.dhppExpiry           || 'N/A',
  bordetellaExpiry:      petData.bordetellaExpiry     || 'N/A',
  currentMedications:    petData.currentMedications   || 'None',
  medicationDosages:     petData.medicationDosages    || 'N/A',
  labResultsSummary:     petData.labResultsSummary    || 'None',
  proceduresDone:        petData.proceduresDone       || 'None',
  healthStatus:          petData.healthStatus         || 'N/A',
  nextAppointmentDate:   petData.nextAppointmentDate  || 'N/A',
  nextAppointmentReason: petData.nextAppointmentReason|| 'N/A',
  followUpInstructions:  petData.followUpInstructions || 'None',
  urgentAlerts:          urgentAlerts.join('; ')      || 'None',
  alertLevel,
  healthAnalysis:        healthAnalysis.slice(0, 400),
  processedAt:           new Date().toISOString()
}}];

